// Handle both n8n v2 webhook (body in .json.body) and direct JSON
const raw = $input.first().json;
const body = typeof raw.body === 'string' ? JSON.parse(raw.body) : (raw.body ?? raw);

// Safe extraction of Meta WhatsApp Payload
let message = '';
let phone = '';
let is_message = false;

try {
  if (body.entry && body.entry[0].changes && body.entry[0].changes[0].value.messages) {
    const msgObj = body.entry[0].changes[0].value.messages[0];
    if (msgObj.type === 'text') {
      message = msgObj.text.body;
      phone = msgObj.from;
      is_message = true;
    }
  }
} catch(e) {}

return [{ json: { message: message, phone: phone, is_message: is_message } }];

const raw = $input.first().json;
const phone = $('Extract Meta Payload').first().json.phone;
const original = $('Extract Meta Payload').first().json.message;
const rewritten = raw.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || 'REWRITE_FAILED';
const isGreeting = rewritten === 'GREETING_ONLY';

return [{ json: { original_message: original, phone: phone, rewritten_query: rewritten, is_greeting: isGreeting } }];

const crypto = require('crypto');
const item = $input.first();
const headers = item.json.headers;
const rawBody = typeof item.json.body === 'string' ? item.json.body : JSON.stringify(item.json.body);
const signatureHeader = headers['x-hub-signature-256'];

// Modern n8n environment variable access
const secret = $env.META_APP_SECRET;

if (!secret) throw new Error("META_APP_SECRET env var is missing in n8n!");
if (!signatureHeader) throw new Error("Missing x-hub-signature-256 header!");

const expectedSignature = 'sha256=' + crypto.createHmac('sha256', secret).update(rawBody).digest('hex');

// 2026 SECURE BEST PRACTICE: Prevent timing attacks
const a = Buffer.from(signatureHeader);
const b = Buffer.from(expectedSignature);

if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
    throw new Error("Signature mismatch! Potential webhook forgery.");
}

return $input.all();

